DROP TRIGGER IF EXISTS tbiu_sc_mem_m_ucf_district ON sc_mem_m_ucf_district CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_mem_m_ucf_district() RETURNS trigger AS $BODY$
BEGIN
  if coalesce(trim(both NEW.district_code)::text, '') = '' then
    select max(district_code) into STRICT NEW.district_code
    from sc_mem_m_ucf_district
    where (province_code = NEW.province_code);
    NEW.district_code := to_char( coalesce((trim(both NEW.district_code))::numeric ,0) + 1 ,'00');
  end if;
RETURN NEW;
end
